# --- plot helper (hidden) — one bar per opcode, drawn from the student's alu ---
# Calls alu(a, b, op) for op = 0..3 and draws a bar for each. If alu isn't
# ready, each bar falls back to a plain-Python answer so the panel never blanks.
def __bar(op, height):
    left = op + 0.15
    right = op + 0.85
    return [[left, 0], [left, height], [right, height], [right, 0]]

def __plot(a, b):
    names = ["ADD", "SUB", "AND", "OR"]
    fallback = [(a + b) & 0xF, (a - b) & 0xF, a & b, a | b]
    alu = globals().get("alu")
    series = []
    for op in range(4):
        h = fallback[op]
        if alu is not None:
            try:
                v = alu(a, b, op)
                if isinstance(v, int):
                    h = v
            except Exception:
                pass
        series.append({"name": names[op], "points": __bar(op, h), "highlight": True})
    return series
